'use client';

/**
 * Página de Configurações VOIP
 */

import { useState } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { ArrowLeft, Phone, Save, AlertCircle } from 'lucide-react';
import Link from 'next/link';
import { toast } from '@/hooks/use-toast';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';

export default function VOIPSettingsPage() {
    const [accountSid, setAccountSid] = useState('');
    const [authToken, setAuthToken] = useState('');
    const [phoneNumber, setPhoneNumber] = useState('');
    const [isActive, setIsActive] = useState(false);
    const [isSaving, setIsSaving] = useState(false);

    const handleSave = async () => {
        setIsSaving(true);
        try {
            // TODO: Implement save to database
            await new Promise(resolve => setTimeout(resolve, 1000));
            toast({
                title: 'Configurações salvas',
                description: 'As credenciais VOIP foram atualizadas.',
            });
        } catch (error) {
            toast({
                title: 'Erro ao salvar',
                description: 'Não foi possível salvar as configurações.',
                variant: 'destructive'
            });
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <div className="container py-6 space-y-6">
            <div className="flex items-center gap-4">
                <Link href="/calls">
                    <Button variant="ghost" size="icon">
                        <ArrowLeft className="h-4 w-4" />
                    </Button>
                </Link>
                <div>
                    <h1 className="text-3xl font-bold tracking-tight">Configurações VOIP</h1>
                    <p className="text-muted-foreground">Configure as credenciais do Twilio para chamadas.</p>
                </div>
            </div>

            <Alert>
                <AlertCircle className="h-4 w-4" />
                <AlertTitle>Integração Twilio</AlertTitle>
                <AlertDescription>
                    Para utilizar chamadas VOIP, você precisa de uma conta Twilio.
                    Acesse <a href="https://www.twilio.com" target="_blank" rel="noopener noreferrer" className="underline">twilio.com</a> para criar uma conta.
                </AlertDescription>
            </Alert>

            <div className="grid gap-6 md:grid-cols-2">
                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Phone className="h-5 w-5" />
                            Credenciais Twilio
                        </CardTitle>
                        <CardDescription>
                            Configure as credenciais da sua conta Twilio
                        </CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="space-y-2">
                            <Label htmlFor="accountSid">Account SID</Label>
                            <Input
                                id="accountSid"
                                placeholder="ACxxxxxxxxxx..."
                                value={accountSid}
                                onChange={(e) => setAccountSid(e.target.value)}
                            />
                        </div>

                        <div className="space-y-2">
                            <Label htmlFor="authToken">Auth Token</Label>
                            <Input
                                id="authToken"
                                type="password"
                                placeholder="••••••••••••••••"
                                value={authToken}
                                onChange={(e) => setAuthToken(e.target.value)}
                            />
                        </div>

                        <div className="space-y-2">
                            <Label htmlFor="phoneNumber">Número Twilio</Label>
                            <Input
                                id="phoneNumber"
                                placeholder="+1234567890"
                                value={phoneNumber}
                                onChange={(e) => setPhoneNumber(e.target.value)}
                            />
                            <p className="text-xs text-muted-foreground">
                                Número de telefone comprado no Twilio
                            </p>
                        </div>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader>
                        <CardTitle>Configurações</CardTitle>
                        <CardDescription>
                            Opções gerais de chamadas
                        </CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="flex items-center justify-between">
                            <div className="space-y-0.5">
                                <Label>Ativar VOIP</Label>
                                <p className="text-sm text-muted-foreground">
                                    Habilita chamadas telefônicas pelo sistema
                                </p>
                            </div>
                            <Switch
                                checked={isActive}
                                onCheckedChange={setIsActive}
                            />
                        </div>

                        <div className="flex items-center justify-between">
                            <div className="space-y-0.5">
                                <Label>Gravar Chamadas</Label>
                                <p className="text-sm text-muted-foreground">
                                    Salva gravações de todas as chamadas
                                </p>
                            </div>
                            <Switch />
                        </div>

                        <div className="flex items-center justify-between">
                            <div className="space-y-0.5">
                                <Label>Notificações Sonoras</Label>
                                <p className="text-sm text-muted-foreground">
                                    Toca som ao receber chamadas
                                </p>
                            </div>
                            <Switch defaultChecked />
                        </div>
                    </CardContent>
                </Card>
            </div>

            <div className="flex justify-end">
                <Button onClick={handleSave} disabled={isSaving}>
                    <Save className="h-4 w-4 mr-2" />
                    {isSaving ? 'Salvando...' : 'Salvar Configurações'}
                </Button>
            </div>
        </div>
    );
}
